import React, { useState, useEffect, useRef } from 'react';
import CourseCard from '../components/CourseCard';
import config, { getAllCourses } from '../config/config';
import './App.css';  
import { 
  getFeaturedCourses, 
  getStats, 
  checkHealth,
  addSampleCourses 
} from '../services/api';
import { useNavigate } from 'react-router-dom';

const Home = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [backendCourses, setBackendCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [backendStatus, setBackendStatus] = useState('checking');
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  const [activeTab, setActiveTab] = useState('all');
  
  const [stats, setStats] = useState([
    { title: 'Total Notes', value: '0', icon: '📄', key: 'notes' },
    { title: 'PYQs', value: '0', icon: '📝', key: 'pyqs' },
    { title: 'Courses', value: '0', icon: '🎓', key: 'courses' },
    { title: 'Downloads', value: '0', icon: '⬇️', key: 'downloads' },
  ]);
  
  const [animatedStats, setAnimatedStats] = useState([0, 0, 0, 0]);
  const [showAddCoursesBtn, setShowAddCoursesBtn] = useState(false);
  
  const [latestMaterials, setLatestMaterials] = useState([]);
  const [materialsLoading, setMaterialsLoading] = useState(true);
  const [materialsError, setMaterialsError] = useState('');
  
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [hoveredCard, setHoveredCard] = useState(null);
  
  const statsRef = useRef(null);
  const navigate = useNavigate();
  
  const staticCourses = getAllCourses();

  // Handle scroll for back to top button
  useEffect(() => {
    const handleScroll = () => {
      setShowScrollBtn(window.scrollY > 400);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleResize = () => {
      setWindowWidth(window.innerWidth);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    checkBackend();
    fetchData();
    fetchLatestMaterials();
  }, []);

  // Intersection Observer for stats animation
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            animateStats();
          }
        });
      },
      { threshold: 0.5 }
    );

    if (statsRef.current) {
      observer.observe(statsRef.current);
    }

    return () => observer.disconnect();
  }, [stats]);

  const animateStats = () => {
    const targetValues = stats.map(s => parseInt(s.value) || 0);
    const duration = 2000;
    const steps = 60;
    let currentStep = 0;

    const interval = setInterval(() => {
      currentStep++;
      const progress = Math.min(currentStep / steps, 1);
      
      const newValues = targetValues.map(target => 
        Math.floor(target * progress)
      );
      
      setAnimatedStats(newValues);

      if (currentStep >= steps) {
        clearInterval(interval);
      }
    }, duration / steps);
  };

  const fetchLatestMaterials = async () => {
    try {
      setMaterialsLoading(true);
      setMaterialsError('');
      
      const response = await fetch('http://localhost:5000/api/materials');
      const data = await response.json();
      
      if (data.success) {
        const transformedMaterials = data.materials.map(m => ({
          ...m,
          course_name: m.course || m.course_name || 'Unknown',
          display_course: m.course || m.course_name || 'Unknown',
          uploaded_at: m.uploaded_at || new Date().toISOString()
        }));
        
        setLatestMaterials(transformedMaterials.slice(0, 8));
      } else {
        setMaterialsError(data.error || 'Failed to fetch materials');
      }
    } catch (error) {
      console.error('Materials fetch error:', error);
      setMaterialsError('Connection failed. Check if backend is running on port 5000');
    } finally {
      setMaterialsLoading(false);
    }
  };

  const handleMaterialClick = async (material) => {
    try {
      const token = localStorage.getItem('study_portal_token');
      
      if (!token) {
        const shouldLogin = window.confirm('Please login first to download materials. Go to login page?');
        if (shouldLogin) {
          navigate('/login');
        }
        return;
      }
      
      const downloadBtn = document.getElementById(`download-${material.id}`);
      if (downloadBtn) {
        downloadBtn.textContent = '⏳ Downloading...';
        downloadBtn.disabled = true;
        downloadBtn.classList.add('downloading');
      }
      
      const downloadUrl = `http://localhost:5000/api/notes/${material.id}/download`;
      
      const response = await fetch(downloadUrl, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
        }
      });
      
      if (!response.ok) {
        if (response.status === 401) {
          throw new Error('Session expired. Please login again.');
        } else if (response.status === 404) {
          throw new Error('File not found on server');
        } else {
          throw new Error(`Download failed (${response.status})`);
        }
      }
      
      const blob = await response.blob();
      
      const contentDisposition = response.headers.get('Content-Disposition');
      let filename = material.file_name || `${material.title}.pdf`;
      
      if (contentDisposition) {
        const match = contentDisposition.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
        if (match && match[1]) {
          filename = match[1].replace(/['"]/g, '');
        }
      }
      
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      
      showToast('✅ Download started!', 'success');
      
    } catch (error) {
      console.error('❌ Download error:', error);
      
      if (error.message.includes('401')) {
        showToast('⚠️ Session expired. Please login again.', 'error');
        localStorage.removeItem('study_portal_token');
        navigate('/login');
      } else if (error.message.includes('404')) {
        showToast('❌ File not found on server.', 'error');
      } else {
        showToast(`❌ Download failed: ${error.message}`, 'error');
      }
    } finally {
      const downloadBtn = document.getElementById(`download-${material.id}`);
      if (downloadBtn) {
        downloadBtn.textContent = 'Download';
        downloadBtn.disabled = false;
        downloadBtn.classList.remove('downloading');
      }
    }
  };

  // Toast notification function
  const showToast = (message, type = 'success') => {
    const toast = document.createElement('div');
    toast.className = `toast-message ${type}`;
    toast.textContent = message;
    document.body.appendChild(toast);
    
    setTimeout(() => {
      toast.classList.add('fade-out');
      setTimeout(() => toast.remove(), 300);
    }, 3000);
  };

  const checkBackend = async () => {
    try {
      const health = await checkHealth();
      setBackendStatus('connected');
      console.log('✅ Backend connected:', health);
      
      if (health.course_count === 0) {
        setShowAddCoursesBtn(true);
      }
    } catch (error) {
      setBackendStatus('disconnected');
      console.error('❌ Backend connection failed:', error);
    }
  };

  const handleAddSampleCourses = async () => {
    try {
      setLoading(true);
      const result = await addSampleCourses();
      showToast(`✅ ${result.message}`, 'success');
      setShowAddCoursesBtn(false);
      fetchData();
    } catch (error) {
      showToast('❌ Failed to add sample courses', 'error');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async () => {
    try {
      const coursesData = await getFeaturedCourses(8);
      
      const transformedCourses = coursesData.courses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branch || 'General',
        semester: course.semester || 'All',
        code: course.code || 'GEN',
        notes: course.notes || 0,
        pyqs: course.pyqs || 0,
        description: course.description || 'Study materials',
        created_at: course.created_at,
        icon: course.icon || '📚',
        color: course.color || '#4f46e5'
      }));
      
      setBackendCourses(transformedCourses);
      
      const statsData = await getStats();
      setStats([
        { 
          title: 'Total Notes', 
          value: `${statsData.totalNotes || config.STATS_DEFAULTS.totalNotes}`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${statsData.totalPYQs || config.STATS_DEFAULTS.totalPYQs}`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${statsData.totalCourses || config.STATS_DEFAULTS.totalCourses}`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${statsData.totalDownloads || config.STATS_DEFAULTS.totalDownloads}`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
    } catch (error) {
      console.error('Error fetching data:', error);
      
      setBackendCourses([]);
      
      setStats([
        { 
          title: 'Total Notes', 
          value: `${config.STATS_DEFAULTS.totalNotes}`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${config.STATS_DEFAULTS.totalPYQs}`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${config.STATS_DEFAULTS.totalCourses}`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${config.STATS_DEFAULTS.totalDownloads}`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
      setBackendStatus('disconnected');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setSearchQuery('');
    }
  };

  const handleCourseClick = (courseId) => {
    navigate(`/course/${courseId}`);
  };

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const displayCourses = backendStatus === 'connected' && backendCourses.length > 0 
    ? backendCourses 
    : staticCourses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branches?.[0] || 'General',
        semester: 'All',
        code: course.name.substring(0, 4).toUpperCase(),
        notes: Math.floor(config.STATS_DEFAULTS.totalNotes / 5),
        pyqs: Math.floor(config.STATS_DEFAULTS.totalPYQs / 5),
        description: course.description,
        icon: course.icon || '📚',
        color: course.color || '#4f46e5',
        duration: course.duration
      }));

  const features = [
    { title: 'Updated Content', desc: 'Regularly updated materials', icon: '✅' },
    { title: 'Easy Search', desc: 'Find materials quickly', icon: '🔍' },
    { title: 'Mobile Friendly', desc: 'Access on any device', icon: '📱' },
    { title: 'Free Forever', desc: 'All resources free', icon: '🆓' },
    { title: 'Expert Teachers', desc: 'Content by experienced educators', icon: '👨‍🏫' },
    { title: '24/7 Access', desc: 'Study anytime, anywhere', icon: '⏰' },
  ];

  const getMaterialTypeColor = (type) => {
    switch (type?.toLowerCase()) {
      case 'notes': return { background: '#dbeafe', color: '#1d4ed8' };
      case 'pyq': return { background: '#fef3c7', color: '#d97706' };
      case 'syllabus': return { background: '#dcfce7', color: '#15803d' };
      case 'imp_questions': return { background: '#f3e8ff', color: '#7c3aed' };
      default: return { background: '#f1f5f9', color: '#64748b' };
    }
  };

  const filteredMaterials = activeTab === 'all' 
    ? latestMaterials 
    : latestMaterials.filter(m => {
        const type = m.material_type || m.note_type;
        return type?.toLowerCase() === activeTab.toLowerCase();
      });

  const tabs = [
    { id: 'all', label: 'All', icon: '📋' },
    { id: 'notes', label: 'Notes', icon: '📄' },
    { id: 'pyq', label: 'PYQs', icon: '📝' },
    { id: 'syllabus', label: 'Syllabus', icon: '📚' },
  ];

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero-section">
        <div className="hero-particles"></div>
        <div className="hero-content">
          <div className="hero-badge">
            <span className={`status-indicator ${backendStatus}`}></span>
            <span className="status-text">
              {backendStatus === 'connected' ? 'Live Server' : 'Demo Mode'}
            </span>
          </div>
          
          <h1 className="hero-title">
            Welcome to <span className="hero-highlight">{config.APP_NAME}</span>
          </h1>
          
          <p className="hero-subtitle">
            Your complete learning ecosystem. Access notes, previous year papers, 
            syllabus, and more — all in one place, absolutely free.
          </p>
          
          <form className="hero-search-container" onSubmit={handleSearch}>
            <div className="search-wrapper">
              <span className="search-icon">🔍</span>
              <input
                type="text"
                className="search-input"
                placeholder="Search for courses, notes, PYQs, topics..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <button type="submit" className="search-button">
              Search
            </button>
          </form>

          <div className="hero-cta">
            <button className="cta-button primary" onClick={() => navigate('/courses')}>
              Browse Courses
            </button>
            <button className="cta-button secondary" onClick={() => navigate('/about')}>
              Learn More
            </button>
          </div>

          {showAddCoursesBtn && backendStatus === 'connected' && (
            <button 
              className="add-courses-btn"
              onClick={handleAddSampleCourses}
              disabled={loading}
            >
              {loading ? (
                <>
                  <span className="spinner-small"></span>
                  Adding...
                </>
              ) : (
                <>
                  <span>➕</span>
                  Add Sample Courses
                </>
              )}
            </button>
          )}
        </div>

        {/* Wave Divider */}
        <div className="hero-wave">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1440 320" preserveAspectRatio="none">
            <path fill="#ffffff" fillOpacity="1" d="M0,96L48,112C96,128,192,160,288,160C384,160,480,128,576,122.7C672,117,768,139,864,154.7C960,171,1056,181,1152,170.7C1248,160,1344,128,1392,112L1440,96L1440,320L1392,320C1344,320,1248,320,1152,320C1056,320,960,320,864,320C768,320,672,320,576,320C480,320,384,320,288,320C192,320,96,320,48,320L0,320Z"></path>
          </svg>
        </div>
      </section>

      {/* Stats Section */}
      <section className="stats-section" ref={statsRef}>
        <div className="stats-grid">
          {stats.map((stat, index) => (
            <div key={index} className="stat-card" style={{animationDelay: `${index * 0.1}s`}}>
              <div className="stat-icon-wrapper">
                <span className="stat-icon">{stat.icon}</span>
              </div>
              <div className="stat-content">
                <h3 className="stat-number">
                  {animatedStats[index] || stat.value}
                  <span className="stat-plus">+</span>
                </h3>
                <p className="stat-label">{stat.title}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Popular Courses Section */}
      <section className="courses-section">
        <div className="section-header">
          <h2 className="section-title">Popular Courses</h2>
          <p className="section-subtitle">Most accessed courses by students like you</p>
        </div>
        
        {loading ? (
          <div className="loading-container">
            <div className="loading-spinner"></div>
            <p>Loading courses...</p>
          </div>
        ) : displayCourses.length === 0 && backendStatus === 'connected' ? (
          <div className="empty-state">
            <div className="empty-icon">📚</div>
            <h3>No Courses Found</h3>
            <p>Add sample courses to get started</p>
            <button 
              className="empty-state-btn"
              onClick={handleAddSampleCourses}
            >
              Add Sample Courses
            </button>
          </div>
        ) : (
          <>
            <div className="courses-grid">
              {displayCourses.slice(0, 4).map(course => (
                <div 
                  key={course.id} 
                  className={`course-card-wrapper ${hoveredCard === course.id ? 'hovered' : ''}`}
                  onClick={() => handleCourseClick(course.id)}
                  onMouseEnter={() => setHoveredCard(course.id)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <CourseCard 
                    course={{
                      ...course,
                      onCourseClick: () => handleCourseClick(course.id)
                    }}
                  />
                </div>
              ))}
            </div>
            
            <div className="section-footer">
              <button 
                className="view-all-btn"
                onClick={() => navigate('/courses')}
              >
                View All Courses <span className="arrow">→</span>
              </button>
            </div>
          </>
        )}
      </section>

      {/* Latest Materials Section */}
      <section className="materials-section">
        <div className="section-header">
          <h2 className="section-title">Latest Study Materials</h2>
          <p className="section-subtitle">Recently uploaded by educators and students</p>
          
          {/* Material Tabs */}
          <div className="materials-tabs">
            {tabs.map(tab => (
              <button 
                key={tab.id}
                className={`tab-btn ${activeTab === tab.id ? 'active' : ''}`}
                onClick={() => setActiveTab(tab.id)}
              >
                <span className="tab-icon">{tab.icon}</span>
                <span className="tab-label">{tab.label}</span>
              </button>
            ))}
          </div>
        </div>
        
        {materialsLoading ? (
          <div className="loading-container">
            <div className="loading-spinner"></div>
            <p>Loading latest materials...</p>
          </div>
        ) : materialsError ? (
          <div className="error-state">
            <div className="error-icon">⚠️</div>
            <h3>Connection Error</h3>
            <p>{materialsError}</p>
            <button 
              className="retry-btn"
              onClick={fetchLatestMaterials}
            >
              Try Again
            </button>
          </div>
        ) : filteredMaterials.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">📭</div>
            <h3>No Materials Found</h3>
            <p>Check back later for new content</p>
          </div>
        ) : (
          <>
            <div className="materials-grid">
              {filteredMaterials.map((material) => {
                const typeColor = getMaterialTypeColor(material.material_type || material.note_type);
                const isNew = material.uploaded_at && 
                  (new Date() - new Date(material.uploaded_at)) < 7 * 24 * 60 * 60 * 1000;
                
                return (
                  <div 
                    key={material.id} 
                    className="material-card"
                    onMouseEnter={() => setHoveredCard(material.id)}
                    onMouseLeave={() => setHoveredCard(null)}
                  >
                    <div className="material-badge" style={typeColor}>
                      {(material.material_type || material.note_type || 'notes').toUpperCase()}
                      {isNew && <span className="new-badge">NEW</span>}
                    </div>
                    
                    <div className="material-content">
                      <h4 className="material-title">{material.title}</h4>
                      
                      <div className="material-course-info">
                        <span className="course-tag">{material.course_name || 'General'}</span>
                      </div>
                      
                      <div className="material-meta">
                        <span className="material-author">
                          <span className="meta-icon">👤</span> {material.user_name || 'Educator'}
                        </span>
                        <span className="material-date">
                          <span className="meta-icon">📅</span> 
                          {material.uploaded_at ? new Date(material.uploaded_at).toLocaleDateString() : 'N/A'}
                        </span>
                      </div>
                      
                      <div className="material-footer">
                        <div className="material-stats">
                          <span className="stat-item" title="Views">
                            <span className="stat-icon">👁️</span> {material.views || 0}
                          </span>
                          <span className="stat-item" title="Downloads">
                            <span className="stat-icon">⬇️</span> {material.downloads || 0}
                          </span>
                        </div>
                        
                        <button 
                          id={`download-${material.id}`}
                          className="download-btn"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleMaterialClick(material);
                          }}
                        >
                          <span className="btn-text">Download</span>
                          <span className="btn-icon">⬇️</span>
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
            
            <div className="section-footer">
              <button 
                className="view-all-btn"
                onClick={() => navigate('/materials')}
              >
                Browse All Materials <span className="arrow">→</span>
              </button>
            </div>
          </>
        )}
      </section>

      {/* Features Grid */}
      <section className="features-section">
        <div className="section-header">
          <h2 className="section-title">Why Students Love Us</h2>
          <p className="section-subtitle">Everything you need to ace your exams</p>
        </div>
        
        <div className="features-grid">
          {features.map((feature, index) => (
            <div key={index} className="feature-card" style={{animationDelay: `${index * 0.1}s`}}>
              <div className="feature-icon-wrapper">
                <span className="feature-icon">{feature.icon}</span>
              </div>
              <h3 className="feature-title">{feature.title}</h3>
              <p className="feature-desc">{feature.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Testimonials Section */}
      <section className="testimonials-section">
        <div className="section-header">
          <h2 className="section-title">What Students Say</h2>
          <p className="section-subtitle">Join thousands of successful learners</p>
        </div>
        
        <div className="testimonials-grid">
          <div className="testimonial-card">
            <div className="testimonial-quote">"</div>
            <p className="testimonial-text">
              This platform helped me prepare for my exams with high-quality notes and previous year papers. Highly recommended!
            </p>
            <div className="testimonial-author">
              <div className="author-avatar">👨‍🎓</div>
              <div className="author-info">
                <h4>Rahul Sharma</h4>
                <p>Computer Science, 3rd Year</p>
              </div>
            </div>
          </div>
          
          <div className="testimonial-card">
            <div className="testimonial-quote">"</div>
            <p className="testimonial-text">
              The best free resource for engineering students. Everything is well-organized and easy to find.
            </p>
            <div className="testimonial-author">
              <div className="author-avatar">👩‍🎓</div>
              <div className="author-info">
                <h4>Priya Patel</h4>
                <p>Electronics, 4th Year</p>
              </div>
            </div>
          </div>
          
          <div className="testimonial-card">
            <div className="testimonial-quote">"</div>
            <p className="testimonial-text">
              I love how easy it is to download materials. The PYQs section saved me during semester exams!
            </p>
            <div className="testimonial-author">
              <div className="author-avatar">👨‍🎓</div>
              <div className="author-info">
                <h4>Amit Kumar</h4>
                <p>Mechanical, 2nd Year</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Newsletter Section */}
      <section className="newsletter-section">
        <div className="newsletter-container">
          <h2 className="newsletter-title">Stay Updated</h2>
          <p className="newsletter-subtitle">
            Get notified when new materials are added. No spam, unsubscribe anytime.
          </p>
          
          <form className="newsletter-form" onSubmit={(e) => e.preventDefault()}>
            <input 
              type="email" 
              placeholder="Enter your email address" 
              className="newsletter-input"
              required
            />
            <button type="submit" className="newsletter-btn">
              Subscribe
            </button>
          </form>
        </div>
      </section>

      {/* Back to Top Button */}
      {showScrollBtn && (
        <button className="scroll-top-btn" onClick={scrollToTop} title="Back to top">
          ↑
        </button>
      )}

      {/* Backend Status Bar */}
      <div className="backend-status-bar">
        <div className="status-content">
          <div className="status-left">
            <span className={`status-dot ${backendStatus}`}></span>
            <span>Backend: <strong>{backendStatus === 'connected' ? 'Connected' : 'Disconnected'}</strong></span>
          </div>
          <div className="status-right">
            <span className="status-item">📚 Courses: {displayCourses.length}</span>
            <span className="status-item">📄 Materials: {latestMaterials.length}</span>
            <span className="status-item">⚡ Mode: {backendStatus === 'connected' ? 'Live' : 'Demo'}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Home;
